// Parse manual sync request (same payload as init-sync)
const body = $input.first().json.body || $input.first().json;
const operatorId = body.operator_id;
const connectionId = body.connection_id;
const hospitableCustomerId = body.hospitable_customer_id;
const hospitableConnectionId = body.hospitable_connection_id;

if (!operatorId || !hospitableCustomerId) {
  throw new Error('Missing operator_id or hospitable_customer_id');
}

return [{
  json: {
    operatorId,
    connectionId,
    hospitableCustomerId,
    hospitableConnectionId
  }
}];

// Same transform as init-sync
const response = $input.first().json;
const listings = response.data || response.listings || [];
const operatorId = $('Parse Manual Sync Payload').first().json.operatorId;
const hospitableCustomerId = $('Parse Manual Sync Payload').first().json.hospitableCustomerId;
const hospitableConnectionId = $('Parse Manual Sync Payload').first().json.hospitableConnectionId;
const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;
let upserted = 0;

for (const listing of listings) {
  const prop = {
    operator_id: operatorId,
    source: 'airbnb',
    status: 'completed',
    listing_status: 'listed',
    hospitable_property_id: listing.id || listing.listing_id,
    hospitable_connected: true,
    hospitable_last_sync_at: new Date().toISOString(),
    hospitable_sync_status: 'completed',
    hospitable_connection_id: hospitableConnectionId,
    hospitable_customer_id: hospitableCustomerId,
    public_title: listing.name || listing.title || '',
    description: listing.description || '',
    address: listing.address?.full || '',
    city: listing.address?.city || '',
    country: listing.address?.country || '',
    max_guests: listing.max_guests || 4,
    base_rate_amount: listing.base_price || 100,
    images: (listing.photos || []).map((p, i) => ({ url: p.url || p, caption: '', order: i }))
  };

  const hpid = prop.hospitable_property_id;
  const existing = await fetch(
    `${supabaseUrl}/rest/v1/nfs_properties?hospitable_property_id=eq.${hpid}&select=id`,
    { headers: { 'apikey': serviceKey, 'Authorization': `Bearer ${serviceKey}`, 'Accept': 'application/json' } }
  ).then(r => r.json());

  if (existing?.length > 0) {
    await fetch(`${supabaseUrl}/rest/v1/nfs_properties?id=eq.${existing[0].id}`, {
      method: 'PATCH',
      headers: { 'apikey': serviceKey, 'Authorization': `Bearer ${serviceKey}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify(prop)
    });
  } else {
    await fetch(`${supabaseUrl}/rest/v1/nfs_properties`, {
      method: 'POST',
      headers: { 'apikey': serviceKey, 'Authorization': `Bearer ${serviceKey}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify(prop)
    });
  }
  upserted++;
}

return [{ json: { propertiesUpserted: upserted } }];
